sharedShellModule.publicApi:
export type UnifiedFieldType = 'dynamic-label' | 'datarepeater' | 'razor';

export interface UnifiedDesignerCtx {
  fieldKey: string;
  formId: number | string;
  widgetSlug: 'widget-dynamic-label' | 'widget-datarepeater' | 'widget-razor-widget';
  fieldType: UnifiedFieldType;
  initialProps: Record<string, any>;
  /** Mutable working copy the shell merges per-tab drafts into. */
  draft: Record<string, any>;
  /** Cached lookups shared across tabs (table list, KB hits). */
  cache: { tables?: Array<{name:string;rowCount:number}>; columnsByTable?: Record<string, any[]>; };
  /** Switch focus to another tab (used by Data tab after "Apply data view"). */
  focusTab(tabId: string): void;
  /** Stage a partial merge from any tab without committing to the field. */
  stageDraft(patch: Record<string, any>, opts?: { toast?: string }): void;
  /** Toggle the right-side AI panel programmatically. */
  toggleAi(open?: boolean): void;
}

export interface UnifiedTabApi {
  /** Called by the shell when Apply is clicked. Return the partial widgetProps this tab owns. */
  getDraft(): Record<string, any>;
  /** Shell pushes the merged draft back when other tabs stage changes (e.g. Data tab seeds masterQuery). */
  setProps(p: Record<string, any>): void;
  /** Whether this tab has unsaved edits since last setProps()/mount. */
  isDirty(): boolean;
  /** Optional teardown hook (close iframes, abort fetches). */
  destroy?(): void;
}

export interface UnifiedTabSpec {
  id: string;
  label: string;
  /** Optional icon char/SVG; rendered in tab strip. */
  icon?: string;
  /** Built-in tabs ('current-settings', 'data') ship with the shell; host body tabs are added by widget. */
  mount(host: HTMLElement, ctx: UnifiedDesignerCtx): UnifiedTabApi;
}

export interface UnifiedDesignerOpts {
  fieldKey: string;
  fieldType: UnifiedFieldType;
  widgetSlug: UnifiedDesignerCtx['widgetSlug'];
  formId: number | string;
  currentProps: Record<string, any>;
  /** Extra tabs supplied by the widget (host body). Built-in Current Settings + Data are auto-prepended. */
  tabs: UnifiedTabSpec[];
  /** Default tab id to focus on open (defaults to first host tab, NOT current-settings). */
  defaultTabId?: string;
  /** Fired once when shell's bottom Apply button is clicked, with the merged draft. */
  onApply(mergedProps: Record<string, any>): void | Promise<void>;
  /** Fired after Apply success or Cancel-confirmed. */
  onClose?(): void;
}

export interface UnifiedDesignerHandle {
  close(force?: boolean): void;
  setActiveTab(id: string): void;
  getDraft(): Record<string, any>;
  /** For widgets that want to push fresh widgetProps mid-flight (e.g. AI Apply). */
  applyExternalDraft(patch: Record<string, any>): void;
}

export function openUnifiedDesigner(opts: UnifiedDesignerOpts): UnifiedDesignerHandle;

/** Built-in tab factories the widget can opt into. */
export function buildCurrentSettingsTab(): UnifiedTabSpec;
export function buildDataTab(): UnifiedTabSpec;
